import api from '@/api/axios'

export async function fetchTasks(params: { page: number; size: number; keyword?: string; priority?: string; status?: string }) {
  const response = await api.get('/tasks', { params })
  return response.data
}

export async function getTask(id: number) {
  const response = await api.get(`/tasks/${id}`)
  return response.data
}

export async function createTask(data: { title: string; description?: string; priority?: string }) {
  const response = await api.post('/tasks', data)
  return response.data
}

export async function updateTask(id: number, data: { title?: string; description?: string; priority?: string }) {
  const response = await api.put(`/tasks/${id}`, data)
  return response.data
}

export async function deleteTask(id: number) {
  await api.delete(`/tasks/${id}`)
}

export async function changeStatus(id: number, status: string) {
  const response = await api.patch(`/tasks/${id}/status`, { status })
  return response.data
}

export async function getTransitions(id: number) {
  const response = await api.get(`/tasks/${id}/transitions`)
  return response.data
}

import { defineStore } from 'pinia'
import { fetchTasks as apiFetchTasks, createTask as apiCreateTask } from '@/api/tasks'

export const useTaskStore = defineStore('task', {
  state: () => ({
    tasks: [] as any[],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
    keyword: '',
    priorityFilter: null as string | null,
    statusFilter: null as string | null,
    loading: false,
    error: null as string | null,
  }),
  actions: {
    async fetchTasks() {
      this.loading = true
      try {
        const data = await apiFetchTasks({
          page: this.page,
          size: this.size,
          keyword: this.keyword,
          priority: this.priorityFilter,
          status: this.statusFilter,
        } as any)
        this.tasks = data.content
        this.page = data.page
        this.size = data.size
        this.totalElements = data.totalElements
        this.totalPages = data.totalPages
        this.error = null
      } catch (e: any) {
        this.error = e.message || 'Failed to fetch tasks'
      } finally {
        this.loading = false
      }
    },
    setKeyword(kw: string) {
      this.keyword = kw
      this.page = 0
    },
    setPriorityFilter(p: string | null) {
      this.priorityFilter = p
      this.page = 0
    },
    setStatusFilter(s: string | null) {
      this.statusFilter = s
      this.page = 0
    },
    setPage(p: number) {
      this.page = p
    },
    async createTask(data: { title: string; description?: string; priority?: string }) {
      await apiCreateTask(data)
      await this.fetchTasks()
    },
  },
})

import { createRouter, createWebHistory } from 'vue-router'

const router = createRouter({
  history: createWebHistory(),
  routes: [
    {
      path: '/',
      name: 'home',
      component: () => import('../views/HomeView.vue'),
    },
    {
      path: '/tasks',
      name: 'tasks',
      component: () => import('../views/TaskListPage.vue'),
    },
  ],
})

export default router

